    summary: {"cols":["Location","Logger / TC S/N","Temp recorded (°C)"],"rows":3},
    tableLabel: "Results summary",
    accept: ["Under representative load and access over the defined period, all positions remain within the band.","Hottest/coldest in-use locations and overall mean recorded.","Worst-case position confirmed for routine monitoring."],
