  "capsulefiller|PQ|0": {
    pre: ["Representative product; CPPs (dosing setting, tamping force, speed) at the qualified recipe.","Validated methods and sampling plan for capsule fill weight (and weight uniformity)."],
    steps: ["Run a representative batch at the qualified CPPs.","Sample capsules across the run per the plan (start/middle/end).","Measure capsule fill weight and calculate fill-weight uniformity (mean, RSD, individuals).","Compare to acceptance.","Record the results in the data table."],
    attach: "Batch record, raw fill-weight data, and the sampling plan.",
    summary: {"cols":["Sample point","Mean fill weight","RSD","Within acceptance?"],"rows":3},
    tableLabel: "Data table",
    accept: ["Capsule fill-weight accuracy and uniformity (mean and RSD, individuals within limit) meet acceptance at the qualified CPPs across the run."],
    note: "Fill-weight uniformity is the capsule CQA driving content uniformity - sampling start/middle/end catches drift as material level or machine temperature changes through the run."
  },
  "capsulefiller|PQ|1": {
    pre: ["Qualified recipe fixed; min and max machine speed to be qualified defined.","Same fill-weight methods."],
    steps: ["Run at the minimum qualified speed and sample/test fill weight and uniformity.","Run at the maximum qualified speed and repeat.","Confirm fill weight stays in spec at both extremes (faster speed can reduce dosing consistency).","Record both speeds in the data table."],
    attach: "Fill-weight data at min and max speed.",
    summary: {"cols":["Speed","Mean fill weight","RSD","In spec?"],"rows":2},
    tableLabel: "Data table",
    accept: ["Capsule fill weight stays within acceptance across the qualified min-max speed range, defining the validated speed window."],
    note: "Qualifying the speed range matters because dosing dwell shortens at high speed and can increase fill variability - the validated window is the production speed range that holds fill-weight quality."
  },
