    steps: ["Define routine airflow/face-velocity and HEPA-integrity monitoring frequency.","Define requalification frequency and triggers (filter change, relocation, layout change).","Confirm documentation.","Record the program in the data table."],
    summary: {"cols":["Element","Frequency / trigger","Basis","Pass/Fail"],"rows":3},
