  "centrifuge|OQ|4": { pre: ["Critical instruments and references available.","Tolerances defined per the URS / GAMP / USP <1058> Group A/B."], steps: ["Before functional testing, verify each critical instrument against NIST-traceable standards (4:1 TUR) per USP <1058>.","Record the as-found error at the process condition (ice-point + range for temperature).","Confirm each is within tolerance; if not, calibrate and re-verify.","Repeat post-study where the instrument drives an acceptance result."], summary: {"cols":["Instrument","Reference","As-found error","Tolerance","Result"],"rowLabels":["Primary measurement","Secondary","Recorder","Reference"]}, tableLabel: "Data table", accept: ["Every critical instrument is within tolerance against NIST-traceable standards (4:1 TUR) per USP <1058> before functional testing.","Out-of-tolerance instruments are corrected and re-verified.","Calibration status is recorded and current."], note: "Calibration verification gates OQ - a drifted speed / temperature reference invalidates every downstream result." },
  "centrifuge|OQ|5": { pre: ["Control-system / program configuration and a calibrated reference."], steps: ["Verify control functions: setpoint entry, display accuracy vs the reference, and phase / program sequencing.","Verify acceleration / deceleration profiles and program recall (if programmable).","Confirm security / access levels where fitted.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Setpoint entry","Display vs reference","Program recall / sequencing","Security / access"]}, tableLabel: "Data table", accept: ["Control functions operate: setpoint entry, display accuracy vs reference, and sequencing are correct.","Program / recipe recall reproduces the saved parameters.","Security / access (where fitted) is correct."], note: "Display accuracy vs an independent reference is the point - the operator acts on the display, so it must match reality." },
