  "centrifuge|PQ|1": { pre: ["Representative load / protocol; instrumented for the critical parameter.","End-to-end acceptance defined."], steps: ["Run the representative load / protocol over routine use (the routine setpoints and durations).","Confirm the critical parameter (speed / temperature / endpoint) meets acceptance under load.","Repeat to show reproducibility.","Record performance."], summary: {"cols":["Run","Critical parameter","Acceptance","Result"],"rowLabels":["Run 1","Run 2","Run 3"]}, tableLabel: "Data table", accept: ["Performance under the representative load / protocol meets acceptance over routine use.","Results are reproducible across runs.","The qualified load / protocol is documented."], note: "PQ proves the unit performs with a real load, not just empty - qualify the representative worst-case load and protocol." },
