  "singleuse|IQ|0": { pre: ["Approved assembly drawing / BOM for the single-use system."], steps: ["Verify the assembly (bag film, tubing, connectors, filters) matches the approved drawing / BOM.","Confirm connector types and orientations match the process (aseptic connectors / welds where required).","Confirm the lot / part numbers and sterility (irradiation) status.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Bag film / chamber","Tubing / connectors","Filters","Lot / sterility status"]}, tableLabel: "Data table", accept: ["The assembly matches the approved drawing / BOM (film, tubing, connectors, filters).","Connector types / orientations match the process.","Lot / part numbers and sterility status are confirmed."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "singleuse|IQ|1": { pre: ["Supplier quality agreement and certificates."], steps: ["Confirm supplier qualification (audit / assessment) and a change-control notification agreement are in place.","Confirm certificates of conformance / analysis and irradiation (sterility) for the lot.","Confirm the assembly drawing / BOM is controlled.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Supplier qualification","Change-notification agreement","CoC / CoA / irradiation cert","Controlled drawing / BOM"]}, tableLabel: "Data table", accept: ["Supplier qualification and a change-control notification agreement are in place.","Lot certificates (CoC / CoA, irradiation / sterility) are on file.","The assembly drawing / BOM is controlled."], note: "With single-use you outsource manufacture but not responsibility - the supplier change-notification agreement is what stops an unvalidated film / connector change reaching your line." },
  "singleuse|IQ|2": { pre: ["Extractables / leachables (E&L) data for the wetted single-use materials."], steps: ["Confirm E&L suitability is documented for the assembly: supplier extractables data (model solvents per USP <665> / BPOG) covering the contact conditions.","Confirm a leachables risk assessment for the process (contact time, temperature, solvent strength, position in train).","Confirm any process-specific study where the risk assessment requires it.","File the E&L package."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Supplier extractables (USP <665> / BPOG)","Contact conditions covered","Leachables risk assessment","Process-specific study (if needed)"]}, tableLabel: "Data table", accept: ["E&L suitability is documented: supplier extractables data (USP <665> / BPOG model solvents) covers the contact conditions.","A leachables risk assessment is completed for the process.","Process-specific data is provided where the risk assessment requires it."], note: "E&L is the single-use Achilles heel - the further upstream and the harsher the solvent / contact, the more the standard supplier data must be backed by a process-specific assessment (USP <665> / <1665>)." },
  "singleuse|IQ|3": { pre: ["Access to calibration records and the documentation set."], steps: ["Build / confirm the instrument inventory (temperature, pH, DO, pressure, level, flow, etc.).","Record cal ID / range / due date for each.","Confirm reference standards and spares.","File the inventory."], summary: {"cols":["Instrument","Cal ID / tag","Range","Cal due","Result"],"rowLabels":["Controlling instruments","Recording instruments","Reference standards","Spares"]}, tableLabel: "Data table", accept: ["A complete instrument inventory is recorded with cal IDs and in-date calibration.","Reference standards and spares are accounted for.","The inventory is filed with the protocol."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." }
