  "mill|IQ|4": { pre: ["Access to calibration records and the documentation set."], steps: ["Build the instrument inventory.","Record cal ID / range / due date for each.","Confirm manuals / documentation are filed.","File the inventory."], summary: {"cols":["Instrument","Cal ID / tag","Range","Cal due","Result"],"rowLabels":["Controlling","Recording","Reference standards","Manuals"]}, tableLabel: "Data table", accept: ["A complete instrument inventory is recorded with cal IDs and in-date calibration.","Manuals / documentation are filed.","The inventory is filed with the protocol."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "mill|OQ|2": { pre: ["Alarm / interlock / safety setpoints from the approved configuration."], steps: ["Challenge each alarm / interlock / safety device (guard / overload).","Confirm each actuates at its setpoint and drives the safe state.","Confirm annunciation / logging.","Record results."], summary: {"cols":["Safety / interlock","Trigger","Response","Result"],"rowLabels":["Guard / lid","Overload","Interlock","E-stop"]}, tableLabel: "Data table", accept: ["Each alarm / interlock / safety device actuates at its setpoint and drives the safe state.","Guard / overload protection prevents an unsafe condition.","Events are annunciated / logged."], note: "Guards / overload / (dust) explosion protection are operator safety - challenge each to its fault condition, do not just confirm wiring." },
  "mill|OQ|3": { pre: ["Critical instruments and references available.","Tolerances defined per the URS / USP <1058>."], steps: ["Before functional testing, verify each critical instrument against NIST-traceable standards (4:1 TUR) per USP <1058>.","Record the as-found error at the process condition.","Confirm within tolerance; if not, calibrate and re-verify.","Repeat post-study where the instrument drives an acceptance result."], summary: {"cols":["Instrument","Reference","As-found error","Tolerance","Result"],"rowLabels":["Primary measurement","Secondary","Recorder","Reference"]}, tableLabel: "Data table", accept: ["Every critical instrument is within tolerance against NIST-traceable standards (4:1 TUR) per USP <1058> before functional testing.","Out-of-tolerance instruments are corrected and re-verified.","Calibration status is recorded and current."], note: "Calibration verification gates OQ - a drifted force / speed / temperature loop invalidates the CQA-driven process PQ that follows." },
  "mill|PQ|1": { pre: ["Representative product / CPPs at the recipe; CQA acceptance defined."], steps: ["Run the required number of consecutive batches at the qualified CPPs.","Confirm the CQAs (particle-size distribution) meet acceptance on every batch.","Assess batch-to-batch consistency (e.g. RSD across batches).","Record results per batch."], summary: {"cols":["Batch","CQA result","Acceptance","Result"],"rowLabels":["Batch 1","Batch 2","Batch 3"]}, tableLabel: "Data table", accept: ["The required consecutive batches each meet the CQA acceptance.","Batch-to-batch consistency is demonstrated (within the defined RSD).","Reproducibility supports Stage 2 PQ per the FDA Process Validation lifecycle (Stage 1 design, Stage 2 PQ, Stage 3 continued verification; PDA TR60)."], note: "Consecutive successful batches are the heart of Stage 2 PQ - reproducibility across batches, not a single good run, is what qualifies the process." },
  "mill|PQ|2": { pre: ["Risk-based scale / load and routine-monitoring rationale (CPPs / CQAs)."], steps: ["Confirm the scale / load (or feed) range to be qualified (e.g. min-max fill, 30 / 50 / 70 % working volume for a blender).","Define routine in-process monitoring (CPPs / CQAs) and the Stage 3 continued-verification plan.","Define requalification triggers (equipment / formulation / scale change) and periodic review.","Document the plan."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Qualified scale / load range","Routine monitoring (CPP / CQA)","Stage 3 continued verification","Requalification triggers"]}, tableLabel: "Data table", accept: ["The qualified scale / load (or feed) range is defined and justified.","Routine monitoring and the Stage 3 continued-verification plan are defined.","Requalification triggers and periodic review are defined. Per ICH Q8(R2) / Q9 / Q10 (QbD - CPPs / CQAs, risk-based)."], note: "Qualify the load range, not just one load - under / over-charging (e.g. a blender) degrades uniformity; the qualified min-max bounds routine use." },
  "tabletpress|IQ|0": { pre: ["Installation drawings / layout and the URS."], steps: ["Walk down the installed unit against the drawings.","Confirm each major sub-system is installed, identified, and connected per design.","Confirm change-parts / tooling and guards are present.","Record any redline."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Turret","Tooling stations","Force / feed systems","De-duster / reject"]}, tableLabel: "Data table", accept: ["The installed configuration matches the controlled drawings / layout.","All major sub-systems are installed, identified, and connected per design.","Any redline is captured and approved."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "tabletpress|IQ|1": { pre: ["Product-contact MOC / finish spec and material certificates."], steps: ["Verify product-contact materials (SS316L), surface finish, and tooling specification (TSM / EU standard, punch / die dimensions) meet the spec; collect MTCs.","Confirm finish is cleanable (Ra) and FDA-compliant for contact.","Confirm seals / change-parts are the qualified items.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Product-contact MOC (SS316L)","Surface finish (Ra)","Tooling spec (TSM/EU)","FDA-compliant"]}, tableLabel: "Data table", accept: ["Product-contact materials (SS316L), finish, and tooling specification (TSM / EU standard, punch / die dimensions) meet the spec with certificates on file.","The finish is cleanable and FDA-compliant.","Change-parts / seals are the qualified items."], note: "Tooling is the dimensional master for the tablet - confirm the TSM / EU tooling spec and punch / die condition at IQ, since worn tooling drives weight / hardness defects." },
  "tabletpress|IQ|2": { pre: ["Instrument list / loop sheets and traceable certificates."], steps: ["Confirm the critical instruments are calibrated and traceable: compression-force, speed, weight, and (in-line) hardness.","Confirm each is range-rated for the process and matches the loop sheet.","Confirm tag / loop IDs.","Record cal IDs / due dates."], summary: {"cols":["Instrument","Cal ID","Range","Cal due","Result"],"rowLabels":["Primary 1","Primary 2","Primary 3","Reference"]}, tableLabel: "Data table", accept: ["Every critical instrument (compression-force, speed, weight, and (in-line) hardness) is calibrated, traceable, and range-rated.","Each matches the loop sheet.","Cal IDs / due dates are recorded. Per USP <1058>."], note: "Compression force is the weight-control CPP on a modern press - confirm the force load cells are calibrated, since force-feedback weight control rides on them." },
