  "coater|IQ|0": { pre: ["Installation drawings / layout and the URS."], steps: ["Walk down the installed unit against the drawings.","Confirm each major sub-system is installed, identified, and connected per design.","Confirm change-parts / tooling and guards are present.","Record any redline."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Pan / drum","Spray guns / manifold","Air handling","Exhaust"]}, tableLabel: "Data table", accept: ["The installed configuration matches the controlled drawings / layout.","All major sub-systems are installed, identified, and connected per design.","Any redline is captured and approved."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "coater|IQ|1": { pre: ["Product-contact MOC / finish spec and material certificates."], steps: ["Verify product-contact materials (SS316L), surface finish, and spray-gun wetted parts meet the spec; collect MTCs.","Confirm finish is cleanable (Ra) and FDA-compliant for contact.","Confirm seals / change-parts are the qualified items.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Product-contact MOC (SS316L)","Surface finish (Ra)","Change-parts / seals","FDA-compliant"]}, tableLabel: "Data table", accept: ["Product-contact materials (SS316L), finish, and spray-gun wetted parts meet the spec with certificates on file.","The finish is cleanable and FDA-compliant.","Change-parts / seals are the qualified items."], note: "SS316L product-contact and a cleanable finish are the GMP basics - confirm against the MTCs." },
  "coater|IQ|2": { pre: ["Instrument list / loop sheets and traceable certificates."], steps: ["Confirm the critical instruments are calibrated and traceable: pan-speed, spray-rate, temperature, and airflow.","Confirm each is range-rated for the process and matches the loop sheet.","Confirm tag / loop IDs.","Record cal IDs / due dates."], summary: {"cols":["Instrument","Cal ID","Range","Cal due","Result"],"rowLabels":["Primary 1","Primary 2","Primary 3","Reference"]}, tableLabel: "Data table", accept: ["Every critical instrument (pan-speed, spray-rate, temperature, and airflow) is calibrated, traceable, and range-rated.","Each matches the loop sheet.","Cal IDs / due dates are recorded. Per USP <1058>."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "coater|IQ|3": { pre: ["Control-system spec, GAMP categorization, data-integrity requirements."], steps: ["Verify the PLC / HMI control system version against the spec (GAMP categorized).","Confirm security, access levels, and the audit trail per 21 CFR Part 11 / EU Annex 11.","Confirm recipe management is access- and version-controlled.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Software version (GAMP)","Security / access","Audit trail (Part 11)","Recipe management"]}, tableLabel: "Data table", accept: ["The control-system version matches the spec and is GAMP categorized.","Security, access, and audit trail meet 21 CFR Part 11 / EU Annex 11.","Recipe management is access- and version-controlled."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "coater|IQ|4": { pre: ["Access to calibration records and the documentation set."], steps: ["Build the instrument inventory.","Record cal ID / range / due date for each.","Confirm manuals / documentation are filed.","File the inventory."], summary: {"cols":["Instrument","Cal ID / tag","Range","Cal due","Result"],"rowLabels":["Controlling","Recording","Reference standards","Manuals"]}, tableLabel: "Data table", accept: ["A complete instrument inventory is recorded with cal IDs and in-date calibration.","Manuals / documentation are filed.","The inventory is filed with the protocol."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "coater|OQ|4": { pre: ["Critical instruments and references available.","Tolerances defined per the URS / USP <1058>."], steps: ["Before functional testing, verify each critical instrument against NIST-traceable standards (4:1 TUR) per USP <1058>.","Record the as-found error at the process condition.","Confirm within tolerance; if not, calibrate and re-verify.","Repeat post-study where the instrument drives an acceptance result."], summary: {"cols":["Instrument","Reference","As-found error","Tolerance","Result"],"rowLabels":["Primary measurement","Secondary","Recorder","Reference"]}, tableLabel: "Data table", accept: ["Every critical instrument is within tolerance against NIST-traceable standards (4:1 TUR) per USP <1058> before functional testing.","Out-of-tolerance instruments are corrected and re-verified.","Calibration status is recorded and current."], note: "Calibration verification gates OQ - a drifted force / speed / temperature loop invalidates the CQA-driven process PQ that follows." },
  "coater|PQ|2": { pre: ["Representative product / CPPs at the recipe; CQA acceptance defined."], steps: ["Run the required number of consecutive batches at the qualified CPPs.","Confirm the CQAs (coat-weight uniformity / appearance) meet acceptance on every batch.","Assess batch-to-batch consistency (e.g. RSD across batches).","Record results per batch."], summary: {"cols":["Batch","CQA result","Acceptance","Result"],"rowLabels":["Batch 1","Batch 2","Batch 3"]}, tableLabel: "Data table", accept: ["The required consecutive batches each meet the CQA acceptance.","Batch-to-batch consistency is demonstrated (within the defined RSD).","Reproducibility supports Stage 2 PQ per the FDA Process Validation lifecycle (Stage 1 design, Stage 2 PQ, Stage 3 continued verification; PDA TR60)."], note: "Consecutive successful batches are the heart of Stage 2 PQ - reproducibility across batches, not a single good run, is what qualifies the process." },
  "capsulefiller|IQ|0": { pre: ["Installation drawings / layout and the URS."], steps: ["Walk down the installed unit against the drawings.","Confirm each major sub-system is installed, identified, and connected per design.","Confirm change-parts / tooling and guards are present.","Record any redline."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Orientation / separation","Dosing system","Closing / ejection","Reject"]}, tableLabel: "Data table", accept: ["The installed configuration matches the controlled drawings / layout.","All major sub-systems are installed, identified, and connected per design.","Any redline is captured and approved."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "capsulefiller|IQ|1": { pre: ["Product-contact MOC / finish spec and material certificates."], steps: ["Verify product-contact materials (SS316L), surface finish, and change-parts (capsule size, dosing disc / tamping pins) meet the spec; collect MTCs.","Confirm finish is cleanable (Ra) and FDA-compliant for contact.","Confirm seals / change-parts are the qualified items.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Product-contact MOC (SS316L)","Surface finish (Ra)","Change-parts / seals","FDA-compliant"]}, tableLabel: "Data table", accept: ["Product-contact materials (SS316L), finish, and change-parts (capsule size, dosing disc / tamping pins) meet the spec with certificates on file.","The finish is cleanable and FDA-compliant.","Change-parts / seals are the qualified items."], note: "SS316L product-contact and a cleanable finish are the GMP basics - confirm against the MTCs." },
