  "capsulefiller|IQ|4": { pre: ["Access to calibration records and the documentation set."], steps: ["Build the instrument inventory.","Record cal ID / range / due date for each.","Confirm manuals / documentation are filed.","File the inventory."], summary: {"cols":["Instrument","Cal ID / tag","Range","Cal due","Result"],"rowLabels":["Controlling","Recording","Reference standards","Manuals"]}, tableLabel: "Data table", accept: ["A complete instrument inventory is recorded with cal IDs and in-date calibration.","Manuals / documentation are filed.","The inventory is filed with the protocol."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "capsulefiller|OQ|3": { pre: ["Alarm / interlock / safety setpoints from the approved configuration."], steps: ["Challenge each alarm / interlock / safety device (guard / overload).","Confirm each actuates at its setpoint and drives the safe state.","Confirm annunciation / logging.","Record results."], summary: {"cols":["Safety / interlock","Trigger","Response","Result"],"rowLabels":["Guard / lid","Overload","Interlock","E-stop"]}, tableLabel: "Data table", accept: ["Each alarm / interlock / safety device actuates at its setpoint and drives the safe state.","Guard / overload protection prevents an unsafe condition.","Events are annunciated / logged."], note: "Guards / overload / (dust) explosion protection are operator safety - challenge each to its fault condition, do not just confirm wiring." },
  "capsulefiller|OQ|4": { pre: ["Critical instruments and references available.","Tolerances defined per the URS / USP <1058>."], steps: ["Before functional testing, verify each critical instrument against NIST-traceable standards (4:1 TUR) per USP <1058>.","Record the as-found error at the process condition.","Confirm within tolerance; if not, calibrate and re-verify.","Repeat post-study where the instrument drives an acceptance result."], summary: {"cols":["Instrument","Reference","As-found error","Tolerance","Result"],"rowLabels":["Primary measurement","Secondary","Recorder","Reference"]}, tableLabel: "Data table", accept: ["Every critical instrument is within tolerance against NIST-traceable standards (4:1 TUR) per USP <1058> before functional testing.","Out-of-tolerance instruments are corrected and re-verified.","Calibration status is recorded and current."], note: "Calibration verification gates OQ - a drifted force / speed / temperature loop invalidates the CQA-driven process PQ that follows." },
