  "hvac|IQ|3": { pre: ["Installation drawings / P&ID / GA and the URS."], steps: ["Walk down the installed system against the drawings.","Confirm each major component (filters / units / pumps / sensors / barriers as applicable) is installed and connected per design.","Confirm utilities and services.","Record any redline."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Major components","Connections","Utilities","Redlines"]}, tableLabel: "Data table", accept: ["The installed configuration matches the controlled drawings.","Major components and utilities are installed per design.","Any redline is captured and approved."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
