  "elementalanalyzer|IQ|2": { pre: ["Reference-standard list and traceable certificates."], steps: ["Confirm multi-element + internal standards are on hand for the working range.","Verify traceability (NIST / ISO 17025) and expiry of each standard / CRM.","Confirm storage conditions (e.g. buffers / CRMs protected, in date).","Record standard IDs / expiry."], summary: {"cols":["Standard / CRM","Traceability","Expiry","Storage","Result"],"rowLabels":["Reference 1","Reference 2","Reference 3","Blank / control"]}, tableLabel: "Data table", accept: ["multi-element + internal standards are on hand, traceable, and in date.","Traceability and expiry are documented.","Storage conditions are met. Per USP <232> / <233> + ICH Q3D / USP <1058> Group C."], note: "Field practice: the qualification is anchored to the standards - verify traceability and expiry first, since an expired / non-traceable CRM invalidates every accuracy result." },
  "elementalanalyzer|IQ|3": { pre: ["Access to calibration records and the documentation set."], steps: ["Build the instrument inventory (controlling and recording instruments / modules).","Record cal ID / range / due date for each.","Confirm manuals / documentation are filed.","File the inventory."], summary: {"cols":["Instrument / module","Cal ID / tag","Range","Cal due","Result"],"rowLabels":["Controlling","Recording","Reference standards","Manuals"]}, tableLabel: "Data table", accept: ["A complete instrument inventory is recorded with cal IDs and in-date calibration.","Manuals / documentation are filed.","The inventory is filed with the protocol."], note: "Installation check: record what is actually installed against the specification; resolve any deviation before OQ." },
  "elementalanalyzer|OQ|0": { pre: ["Tuning / performance solution; multi-element + internal standards."], steps: ["Verify plasma / instrument performance: sensitivity, mass calibration (MS) or wavelength (OES), and stability against the tuning solution.","Confirm resolution / peak shape.","Confirm short-term stability (RSD).","Record results."], summary: {"cols":["Parameter","Reference","Measured","Tolerance","Result"],"rowLabels":["Sensitivity","Mass cal / wavelength","Resolution","Stability (RSD)"]}, tableLabel: "Data table", accept: ["Plasma / instrument performance meets the tuning criteria (sensitivity, mass / wavelength calibration, stability).","Resolution / peak shape is acceptable.","Results are recorded. Per USP <232> / <233> + ICH Q3D / USP <1058> Group C."], note: "Daily performance (sensitivity, mass cal, stability) is the gate for trace elemental work - a poorly tuned plasma misses or mis-quantifies impurities." },
  "elementalanalyzer|OQ|1": { pre: ["Interference-check solutions; collision / reaction cell config."], steps: ["ICP-MS: verify interference control (collision / reaction cell) suppresses the relevant polyatomic interferences.","Verify detector dead-time / cross-calibration.","Confirm interferences are controlled at the analyte masses.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Cell mode","Interference suppression","Detector dead-time","Analyte masses"]}, tableLabel: "Data table", accept: ["Interference control (collision / reaction cell) suppresses the relevant interferences.","Detector dead-time / cross-calibration is correct.","Interferences are controlled at the analyte masses. Per USP <232> / <233> + ICH Q3D / USP <1058> Group C."], note: "Unmanaged polyatomic interferences (e.g. ArCl on As) falsely inflate impurity results - confirm the cell controls them." },
  "elementalanalyzer|OQ|3": { pre: ["Critical instruments / standards and references available.","Tolerances defined per the URS / USP <1058> Group C."], steps: ["Before functional testing, verify each critical instrument / standard against NIST-traceable standards (4:1 TUR) per USP <1058>.","Record the as-found error at the test condition.","Confirm within tolerance; if not, calibrate and re-verify.","Repeat post-study where the instrument drives an acceptance result."], summary: {"cols":["Instrument / standard","Reference","As-found error","Tolerance","Result"],"rowLabels":["Primary","Secondary","Recorder / balance","Reference"]}, tableLabel: "Data table", accept: ["Every critical instrument / standard is within tolerance against NIST-traceable standards (4:1 TUR) per USP <1058> before functional testing.","Out-of-tolerance items are corrected and re-verified.","Calibration status is recorded and current. Per USP <232> / <233> + ICH Q3D / USP <1058> Group C."], note: "Calibration verification gates OQ - a drifted reference invalidates the accuracy / linearity results that follow." },
  "elementalanalyzer|PQ|0": { pre: ["Risk-based routine-control rationale."], steps: ["Define the routine verification (check standard / system suitability) frequency and tolerance, based on risk and use.","Define requalification triggers (repair, relocation, critical change) and periodic-review frequency.","Confirm the plan reflects the intended use.","Document the routine-control and requalification plan."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Routine check / frequency","Tolerance","Requalification triggers","Periodic review"]}, tableLabel: "Data table", accept: ["A risk-based routine verification (frequency + tolerance) is defined and trended.","Requalification triggers and periodic-review frequency are defined.","The plan is documented and approved. Per USP <232> / <233> + ICH Q3D / USP <1058> Group C."], note: "Routine verification + trending keeps the instrument qualified between formal requalifications - tie the frequency to risk and use." },
  "elementalanalyzer|PQ|2": { pre: ["Intended method(s) / monograph conditions."], steps: ["Confirm the intended method conditions (e.g. wavelength, size channels, apparatus / RPM / medium, elements / limits) fall within the qualified range.","Confirm any method-specific suitability where applicable.","Document the qualified-range coverage.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Intended method condition","Qualified range","Within range?","Method suitability"]}, tableLabel: "Data table", accept: ["The intended method conditions fall within the qualified range.","Method-specific suitability passes where applicable.","Coverage is documented. Per USP <232> / <233> + ICH Q3D / USP <1058> Group C."], note: "PQ ties the qualification to the real methods - confirm the intended conditions sit inside what was qualified." },
  "elementalanalyzer|PQ|3": { pre: ["Risk-based routine-control rationale."], steps: ["Define the routine verification (check standard / system suitability) frequency and tolerance, based on risk and use.","Define requalification triggers (repair, relocation, critical change) and periodic-review frequency.","Confirm the plan reflects the intended use.","Document the routine-control and requalification plan."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Routine check / frequency","Tolerance","Requalification triggers","Periodic review"]}, tableLabel: "Data table", accept: ["A risk-based routine verification (frequency + tolerance) is defined and trended.","Requalification triggers and periodic-review frequency are defined.","The plan is documented and approved. Per USP <232> / <233> + ICH Q3D / USP <1058> Group C."], note: "Routine verification + trending keeps the instrument qualified between formal requalifications - tie the frequency to risk and use." },
