  "tablettester|OQ|1": { pre: ["Calibrated tachometer / reference; drop-height check."], steps: ["Verify the friabilator drum rotation speed (e.g. 25 rpm) and the number of drops / revolutions per the standard.","Confirm the drop height per USP <1216>.","Confirm timing / revolution count.","Record results."], summary: {"cols":["Parameter","Reference","Measured","Tolerance","Result"],"rowLabels":["Rotation speed","Drop height","Revolution count","Requirement"]}, tableLabel: "Data table", accept: ["Drum rotation speed, drop height, and revolution count meet USP <1216>.","Timing / count is accurate.","Results are recorded. Per USP <1217> / <1216> / <701> / USP <1058> Group B."], note: "Friability depends on a defined fall - confirm the speed, drop height, and count, since they define the mechanical stress." },
  "tablettester|OQ|3": { pre: ["Calibrated timer; (automated) endpoint-detection config."], steps: ["Verify timing accuracy against a calibrated timer.","Where automated, verify endpoint-detection functions correctly.","Confirm consistent operation.","Record results."], summary: {"cols":["Item","Specified","As-found","Result"],"rowLabels":["Timing accuracy","Endpoint detection","Consistency","Requirement"]}, tableLabel: "Data table", accept: ["Timing is accurate against a calibrated reference.","Automated endpoint detection (where fitted) functions correctly.","Operation is consistent. Per USP <1217> / <1216> / <701> / USP <1058> Group B."], note: "For disintegration / friability the time / endpoint is the result - confirm the timer and any auto-detection." },
  "tablettester|OQ|4": { pre: ["Critical instruments / standards and references available.","Tolerances defined per the URS / USP <1058> Group B."], steps: ["Before functional testing, verify each critical instrument / standard against NIST-traceable standards (4:1 TUR) per USP <1058>.","Record the as-found error at the test condition.","Confirm within tolerance; if not, calibrate and re-verify.","Repeat post-study where the instrument drives an acceptance result."], summary: {"cols":["Instrument / standard","Reference","As-found error","Tolerance","Result"],"rowLabels":["Primary","Secondary","Recorder / balance","Reference"]}, tableLabel: "Data table", accept: ["Every critical instrument / standard is within tolerance against NIST-traceable standards (4:1 TUR) per USP <1058> before functional testing.","Out-of-tolerance items are corrected and re-verified.","Calibration status is recorded and current. Per USP <1217> / <1216> / <701> / USP <1058> Group B."], note: "Calibration verification gates OQ - a drifted reference invalidates the accuracy / linearity results that follow." },
