  "balance|OQ|0": {
    "pre": [
      "Balance warmed up, levelled, draft shield closed; stable environment (no drafts/vibration).",
      "One calibrated test weight near the smallest net weight to be used, traceable, in date.",
      "Repeatability replicate count defined (>= 10)."
    ],
    "steps": [
      "Place the test weight on the pan, record the indication, and remove it; re-zero.",
      "Repeat for at least 10 readings of the same weight, re-zeroing between each.",
      "Record each indication in the data table.",
      "Compute the standard deviation of the indications.",
      "Calculate 2 x SD divided by the smallest net weight and compare to the limit."
    ],
    "attach": "Raw repeatability readings and the SD / minimum-weight calculation.",
    "summary": {
      "cols": [
        "Reading #",
        "Weight value",
        "Indication",
        "Deviation"
      ],
      "rows": 10,
      "rowLabels": [
        "Reading 1",
        "Reading 2",
        "Reading 3",
        "Reading 4",
        "Reading 5",
        "Reading 6",
        "Reading 7",
        "Reading 8",
        "Reading 9",
        "Reading 10"
      ]
    },
    "tableLabel": "Data table",
    "accept": [
      "Weigh one test weight (about half of capacity) at least 10 times under repeatability conditions; record each indication and compute the standard deviation (SD).",
      "Repeatability is satisfactory if 2 x SD divided by the smallest net weight to be used does not exceed 0.10% (USP <41>). If SD < 0.41d (d = scale interval), use 0.41d in the calculation.",
      "The minimum weight is 2000 x SD (or 2000 x 0.41d); document it as the lower bound of the operating range."
    ],
    "note": "Repeatability (not accuracy) sets the MINIMUM WEIGHT - the smallest sample you can weigh and still meet 0.10 % (coverage factor k=2 in current USP <41>). If the SD is below 0.41 d (e.g. 0.041 mg on a 0.1 mg balance), use 0.41 d instead so the minimum weight is not unrealistically small. The Feb-2026 <41>/<1251> revision also makes measurement uncertainty a formal expectation."
  },
  "balance|OQ|1": {
    "pre": [
      "Balance calibrated, levelled, stable.",
      "Calibrated OIML-class weights spanning 5-100 % of capacity, traceable, in date.",
      "Accuracy tolerance defined per USP <41>."
    ],
    "steps": [
      "Select test points across 5-100 % of capacity.",
      "At each point, place the certified weight, allow the reading to stabilize, and record the indication.",
      "Calculate the deviation of each indication from the certified conventional mass.",
      "Compare each deviation to the accuracy tolerance.",
      "Record each point in the data table."
    ],
    "attach": "Raw accuracy readings at each test point.",
    "summary": {
      "cols": [
        "Nominal weight",
        "Conventional mass",
        "Indication",
        "Deviation",
        "Tolerance",
        "Pass/Fail"
      ],
      "rows": 4,
      "rowLabels": [
        "~5% of capacity",
        "~25% of capacity",
        "~50% of capacity",
        "~80% of capacity",
        "~100% of capacity"
      ]
    },
    "tableLabel": "Data table",
    "accept": [
      "Using calibrated weights with mass between 5% and 100% of capacity, each indication is within 0.10% of the conventional mass (USP <41>).",
      "Test points span the operating range; no point is below 5% of capacity.",
      "All weights are traceable (OIML / ASTM / NIST)."
    ],
    "note": "Accuracy is trueness against a known mass; repeatability is scatter - USP <41> needs both. The test weight's maximum permissible error (or calibration uncertainty) must be no more than 1/3 of the accuracy test limit at that point - not just 'small'. ASTM E617 / OIML R111 weights, 5-100 % of capacity."
  },
  "balance|OQ|3": {
    "pre": [
      "Balance levelled and stable.",
      "A single weight ~1/3 to 1/2 of capacity.",
      "Pan reference positions (center + four quadrants) defined; eccentricity limit defined."
    ],
    "steps": [
      "Place the weight at the center of the pan and record the indication.",
      "Move the weight to each of the four quadrants in turn, recording the indication at each.",
      "Calculate the deviation of each off-center reading from the center reading.",
      "Identify the maximum deviation.",
      "Record each position in the data table."
    ],
    "attach": "Raw eccentricity readings (center + quadrants).",
    "summary": {
      "cols": [
        "Position",
        "Indication",
        "Deviation from center",
        "Tolerance",
        "Pass/Fail"
      ],
      "rows": 5,
      "rowLabels": [
        "Centre (reference)",
        "Front-left quadrant",
        "Front-right quadrant",
        "Back-left quadrant",
        "Back-right quadrant"
      ]
    },
    "tableLabel": "Data table",
    "accept": [
      "With the weight at the centre and at each of the four quadrants, the deviation of any off-centre reading from the centre reading does not exceed 0.05% (USP <1251>; half the 0.10% accuracy budget).",
      "The weight used is roughly one-third to one-half of capacity.",
      "Any quadrant out of tolerance is investigated before the balance is released."
    ],
    "note": "Eccentricity catches an out-of-level balance or a worn corner-load mechanism - it's why analysts center the load. The largest deviation usually appears at the corner farthest from level."
  },
