  "benchtopautoclave|OQ|4": {
    "pre": [
      "Chamber empty, door closed; wireless mini data loggers (e.g. Ellab TrackSense Pro or Kaye ValProbe RT) or Type-T thermocouples through the unit’s validation port positioned per the placement map (small chamber: corners, centre, near the drain / coolest point, plus one by the controller sensor); pre-study calibration recorded.",
      "Setpoint and uniformity band defined (e.g. 121.1 +3/-0 C)."
    ],
    "steps": [
      "Position the validation TCs / loggers through the empty chamber per the placement map; record each S/N vs position.",
      "Run the cycle at each sterilization setpoint (121 C / 134 C) and log across the plateau.",
      "Download the data; assess sensor-to-sensor spread and the spread vs the control probe.",
      "Identify the cold spot.",
      "Record hottest, coldest, and mean plateau temperatures."
    ],
    "attach": "Raw / analyzed TC data (all positions, all setpoints), the placement map, and pre/post calibration records.",
    "summary": {
      "cols": [
        "Position",
        "Min",
        "Max",
        "Mean",
        "Result"
      ],
      "rowLabels": [
        "Corners",
        "Centre",
        "Near drain (cold)",
        "By control sensor",
        "Coldest position"
      ]
    },
    "tableLabel": "Data table",
    "accept": [
      "Once at the sterilization setpoint (121 or 134 C), all sensors are within the sterilization band (within ~2 C of each other) during the hold.",
      "The coldest position (usually near the drain / door) is identified for the loaded PQ.",
      "Steam temperature corresponds to the pressure."
    ],
    "note": "Even a small chamber has a cold spot (usually near the drain / door). Map it empty first - the loaded PQ proves F0 there."
  },
  "benchtopautoclave|PQ|1": {
    "pre": [
      "Worst-case load in place; wireless mini data loggers (e.g. Ellab TrackSense Pro or Kaye ValProbe RT) or Type-T thermocouples through the unit’s validation port with penetration TCs at the cold spot and inside a hollow PCD; pre-study calibration recorded.",
      "F0 requirement defined (Z = 10 C, Tref 121.1 C)."
    ],
    "steps": [
      "Load the worst-case configuration; place penetration TCs at the cold spot and inside the hollow-load PCD; record positions.",
      "Run the qualified cycle; log temperature at <= 1 s - 10 s and compute F0 at each position.",
      "Confirm the cold spot and the hollow lumen achieve the required F0.",
      "Record per-position peak temperature and F0."
    ],
    "attach": "Raw / analyzed penetration data (all positions incl. the PCD) and pre/post calibration records.",
    "summary": {
      "cols": [
        "Position",
        "Peak T",
        "F0 (min)",
        "Requirement",
        "Result"
      ],
      "rowLabels": [
        "Cold spot",
        "Hollow PCD lumen",
        "Centre of densest pack",
        "Reference (free)"
      ]
    },
    "tableLabel": "Data table",
    "accept": [
      "F0 at the cold spot and inside the hollow-load PCD lumen meets the requirement (a common overkill target is F0 >= 15 min; reference 121.1 C, z = 10 C).",
      "A wrapped or hollow load lags the chamber, so lethality is proven where steam reaches last.",
      "The paired BI shows no growth."
    ],
    "note": "F0 at the hollow lumen and the cold spot is the real test - a wrapped or hollow load can lag the chamber temperature, so prove lethality where steam arrives last."
  },
  "benchtopautoclave|PQ|5": {
    "pre": [
      "Wrapped / porous worst-case load run through the full cycle including the vacuum drying phase.",
      "Dryness acceptance defined (e.g. residual-moisture gain limit)."
    ],
    "steps": [
      "Weigh representative wrapped / porous packs before the cycle.",
      "Run the full cycle including the Class B vacuum drying phase.",
      "Re-weigh immediately after; compute the moisture gain (and inspect for visible moisture).",
      "Record per-pack moisture gain."
    ],
    "summary": {
      "cols": [
        "Pack",
        "Pre-weight",
        "Post-weight",
        "Moisture gain",
        "Result"
      ],
      "rowLabels": [
        "Wrapped pack 1",
        "Wrapped pack 2",
        "Porous pack",
        "Pouch"
      ]
    },
    "tableLabel": "Data table",
    "accept": [
      "Wrapped / porous loads are dry after the Class B vacuum-dry phase, with weight gain within the limit (a common figure is <= 1 % for textiles).",
      "A wet wrapped pack wicks contamination on storage.",
      "Weigh before and after to quantify residual moisture."
    ],
    "note": "A wet wrapped pack wicks contamination on storage - the Class B vacuum dry must leave wrapped / porous loads dry, so weigh before / after to prove it."
  },
